def route_order(order: dict) -> dict:
    country = order.get("country", "")
    weight_g = order.get("weight_g", 0)
    items = order.get("items", [])
    expedited = order.get("expedited", False)

    is_domestic = (country == "US")
    is_international = not is_domestic

    if weight_g < 500:
        weight_class = "light"
    elif weight_g < 2000:
        weight_class = "medium"
    else:
        weight_class = "heavy"

    is_fragile = any(item.get("fragile", False) for item in items)
    is_heavy = (weight_class == "heavy")

    # Hard rejection: fragile and heavy
    if is_fragile and is_heavy:
        return {
            "action": "reject",
            "carrier": None,
            "service": None,
            "reason": "fragile_too_heavy"
        }

    # Expedited overrides region-specific rules
    if expedited:
        return {
            "action": "dispatch",
            "carrier": "FastShip",
            "service": "next_day",
            "reason": None
        }

    # International orders
    if is_international:
        if weight_class in ("medium", "heavy"):
            return {
                "action": "dispatch",
                "carrier": "GlobalPost",
                "service": "with_customs",
                "reason": None
            }
        else:  # light
            return {
                "action": "dispatch",
                "carrier": "GlobalPost",
                "service": "standard",
                "reason": None
            }

    # Domestic heavy
    if is_domestic and is_heavy:
        return {
            "action": "dispatch",
            "carrier": "DomFreight",
            "service": "freight",
            "reason": None
        }

    # Default
    return {
        "action": "dispatch",
        "carrier": "LocalPost",
        "service": "standard",
        "reason": None
    }
